function addEventListenerForMedia(customMediaScheme){addExclusiveMediaPlayback();addPlaysinlineToVideos();initializeEpubTriggers();convertMediaToCustomMediaScheme(customMediaScheme)}function addExclusiveMediaPlayback(){document.addEventListener("play",function(e){if(e.target instanceof HTMLMediaElement){const allMedia=document.querySelectorAll("video, audio");allMedia.forEach(media=>{if(media!==e.target){media.pause()}})}},true)}function addPlaysinlineToVideos(){const videos=document.querySelectorAll("video");videos.forEach((video,index)=>{if(!video.hasAttribute("playsinline")){video.setAttribute("playsinline","")}})}function initializeEpubTriggers(){const triggers=document.querySelectorAll("epub\\:trigger");triggers.forEach(trigger=>{const observerId=trigger.getAttribute("ev:observer");const referenceId=trigger.getAttribute("ref");const action=trigger.getAttribute("action");const eventType=trigger.getAttribute("ev:event");const observerElement=document.getElementById(observerId);const referenceElement=document.getElementById(referenceId);if(!observerElement||!referenceElement||!eventType||!action){return}observerElement.addEventListener(eventType,()=>{switch(action){case"resume":if(typeof referenceElement.play==="function"){referenceElement.play()}break;case"pause":if(typeof referenceElement.pause==="function"){referenceElement.pause()}break;case"mute":referenceElement.muted=true;break;case"unmute":referenceElement.muted=false;break;case"show":referenceElement.style.visibility="visible";referenceElement.style.display="";break;case"hide":referenceElement.style.visibility="hidden";referenceElement.style.display="none";break;default:console.warn(`Unsupported EPUB action: ${action}`)}})})}function convertMediaToCustomMediaScheme(scheme){if(!scheme){return}const rawScheme=scheme.split(":")[0];if(rawScheme.length===0){return}const targetProtocol=rawScheme+":";const processUrl=url=>{if(!url||url.startsWith(scheme)||url.startsWith("data:"))return null;try{const urlObj=new URL(url,document.baseURI);return urlObj.href.replace(urlObj.protocol,targetProtocol)}catch(e){console.error("Could not process URL:",url,e);return null}};const mediaElements=document.querySelectorAll("video, audio");mediaElements.forEach(element=>{let changed=false;if(element.hasAttribute("src")){const newUrl=processUrl(element.getAttribute("src"));if(newUrl){element.setAttribute("src",newUrl);changed=true}}const sources=element.querySelectorAll("source");sources.forEach(source=>{const newUrl=processUrl(source.getAttribute("src"));if(newUrl){source.setAttribute("src",newUrl);changed=true}});if(changed){element.load()}})}